set-variable.value:
@{
        try {
            // Responses API uses different request/response shapes (input/output_tokens)
            // and does not honor stream_options.include_usage. Skip injection so we do
            // not corrupt a Responses body or trigger a 400 from the AOAI backend.
            if (context.Operation != null && context.Operation.Name == "responses-create") {
                return "not-applicable";
            }

            if (context.Request.Body == null) {
                return "not-applicable";
            }

            var contentType = context.Request.Headers.GetValueOrDefault("Content-Type", "");
            if (!contentType.Contains("json")) {
                return "not-applicable";
            }

            var body = context.Request.Body.As<Newtonsoft.Json.Linq.JObject>(preserveContent: true);

            // Responses API bodies use "input" (string) instead of "messages" (array).
            // Treat any body that has "input" but no "messages" as a Responses shape and skip.
            if (body["messages"] == null && body["input"] != null) {
                return "not-applicable";
            }

            if (body["stream"]?.Value<bool>() != true) {
                return "not-applicable";
            }

            if (body["stream_options"] == null) {
                return "include-usage-injected";
            }

            var streamOptions = body["stream_options"] as Newtonsoft.Json.Linq.JObject;
            if (streamOptions == null) {
                return "include-usage-injected";
            }

            return streamOptions["include_usage"]?.Value<bool>() == true
                ? "client-supplied"
                : "include-usage-injected";
        } catch {
            return "parse-failed";
        }
    }

when.set-body:
@{
                try {
                    var contentType = context.Request.Headers.GetValueOrDefault("Content-Type", "");
                    if (!contentType.Contains("json")) {
                        return context.Request.Body.As<string>(preserveContent: true);
                    }

                    var body = context.Request.Body.As<Newtonsoft.Json.Linq.JObject>(preserveContent: true);

                    // Skip rewriting for Responses-API-shaped bodies (no messages array).
                    if (body["messages"] == null) {
                        return body.ToString();
                    }

                    if (body["stream"]?.Value<bool>() == true) {
                        // Ensure stream_options object exists.
                        if (body["stream_options"] == null) {
                            body["stream_options"] = new Newtonsoft.Json.Linq.JObject();
                        }

                        // Ensure include_usage is set to true.
                        var streamOptions = (Newtonsoft.Json.Linq.JObject)body["stream_options"];
                        if (streamOptions["include_usage"]?.Value<bool>() != true) {
                            streamOptions["include_usage"] = true;
                        }
                    }

                    return body.ToString();
                } catch {
                    // If JSON parsing fails, return original body unchanged.
                    return context.Request.Body.As<string>(preserveContent: true);
                }
            }
